#include <iostream>
#include <string>
using namespace std;

// Basit fonksiyon
int square(int x)
{
    return x * x;
}

// Birden fazla parametre
int add(int a, int b)
{
    return a + b;
}

// Varsayilan parametre
string greet(string name, string greeting = "Merhaba")
{
    return greeting + ", " + name + "!";
}

// Fonksiyon overload
double multiply(double a, double b)
{
    return a * b;
}

int multiply(int a, int b)
{
    return a * b;
}

int main()
{
    cout << "Kare: " << square(5) << endl;
    cout << "Toplam: " << add(3, 7) << endl;
    cout << greet("Ayse") << endl;
    cout << greet("Mehmet", "Selam") << endl;
    cout << "Tam carpim: " << multiply(4, 5) << endl;
    cout << "Ondalik carpim: " << multiply(2.5, 3.0) << endl;

    return 0;
}
